api.example.com {
    @html content_type text/html
    @sc   set_cookie

    cors https://app.example.com methods GET POST OPTIONS headers Content-Type X-Token

    cache_key url

    cache_ttl @html    ttl 1m grace 10m
    cache_ttl default  ttl 10s

    strip_cookies @sc

    header Access-Control-Allow-Origin {http.Origin}
    header X-Client {client_ip}
    header X-Geo    {geo}
    header +cache_status X-Cache
}
